    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// ప్రతి ఎంట్రీని చదవండి మరియు తీయండి    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // పూర్తి మార్గం సృష్టించు        snprintf(full_path, sizeof(full_path), "%s/%s",
